subprograms.code:
function Check_Chip_Id
  (Self   : Sensor;
   Expect : HAL.UInt8 := 16#60#) return Boolean

procedure Configure
  (Self       : Sensor;
   Standby    : Standby_Duration := 0.5;
   Filter     : IRR_Filter_Kind := Off;
   SPI_3_Wire : Boolean := False;
   Success    : out Boolean)

function Humidity
  (Self        : Sensor;
   Value       : Measurement;
   Temperature : Deci_Celsius) return Relative_Humidity

function Pressure
  (Self        : Sensor;
   Value       : Measurement;
   Temperature : Deci_Celsius) return Pressure_Pa

procedure Read_Calibration
  (Self    : in out Sensor;
   Success : out Boolean)

procedure Read_Measurement
  (Self    : Sensor;
   Value   : out Measurement;
   Success : out Boolean)

procedure Reset
  (Self    : Sensor;
   Timer   : not null HAL.Time.Any_Delays;
   Success : out Boolean)

procedure Start
  (Self        : Sensor;
   Mode        : Sensor_Mode := Normal;
   Humidity    : Oversampling_Kind := X1;
   Pressure    : Oversampling_Kind := X1;
   Temperature : Oversampling_Kind := X1;
   Success     : out Boolean)

function Temperature
  (Self  : Sensor;
   Value : Measurement) return Deci_Celsius
